from werkzeug.utils import secure_filename
import os
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'
DATA_DIR = 'data'
RESUME_UPLOAD_DIR = os.path.join(DATA_DIR, 'resume_uploads')
os.makedirs(RESUME_UPLOAD_DIR, exist_ok=True)

# === Helpers for file I/O and data parsing / writing ===

def parse_pipe_line(line, expected_count):
    parts = line.strip().split('|')
    if len(parts) == expected_count:
        return parts
    return None


def read_jobs():
    filepath = os.path.join(DATA_DIR, 'jobs.txt')
    jobs = []
    if not os.path.exists(filepath):
        return jobs
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            parts = parse_pipe_line(line, 9)
            if not parts:
                continue
            try:
                job = {
                    'job_id': int(parts[0]),
                    'title': parts[1],
                    'company_id': int(parts[2]),
                    'location': parts[3],
                    'salary_min': int(parts[4]),
                    'salary_max': int(parts[5]),
                    'category': parts[6],
                    'description': parts[7],
                    'posted_date': parts[8]
                }
                jobs.append(job)
            except ValueError:
                continue
    return jobs


def read_companies():
    filepath = os.path.join(DATA_DIR, 'companies.txt')
    companies = []
    if not os.path.exists(filepath):
        return companies
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            parts = parse_pipe_line(line, 6)
            if not parts:
                continue
            try:
                company = {
                    'company_id': int(parts[0]),
                    'company_name': parts[1],
                    'industry': parts[2],
                    'location': parts[3],
                    'employee_count': int(parts[4]),
                    'description': parts[5]
                }
                companies.append(company)
            except ValueError:
                continue
    return companies


def read_categories():
    filepath = os.path.join(DATA_DIR, 'categories.txt')
    categories = []
    if not os.path.exists(filepath):
        return categories
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            parts = parse_pipe_line(line, 3)
            if not parts:
                continue
            try:
                categories.append({
                    'category_id': int(parts[0]),
                    'category_name': parts[1],
                    'description': parts[2],
                })
            except ValueError:
                continue
    return categories


def read_applications():
    filepath = os.path.join(DATA_DIR, 'applications.txt')
    applications = []
    if not os.path.exists(filepath):
        return applications
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            parts = parse_pipe_line(line, 7)
            if not parts:
                continue
            try:
                application = {
                    'application_id': int(parts[0]),
                    'job_id': int(parts[1]),
                    'applicant_name': parts[2],
                    'applicant_email': parts[3],
                    'status': parts[4],
                    'applied_date': parts[5],
                    'resume_id': int(parts[6])
                }
                applications.append(application)
            except ValueError:
                continue
    return applications


def read_resumes():
    filepath = os.path.join(DATA_DIR, 'resumes.txt')
    resumes = []
    if not os.path.exists(filepath):
        return resumes
    with open(filepath, encoding='utf-8') as f:
        for line in f:
            parts = parse_pipe_line(line, 6)
            if not parts:
                continue
            try:
                resume = {
                    'resume_id': int(parts[0]),
                    'applicant_name': parts[1],
                    'applicant_email': parts[2],
                    'filename': parts[3],
                    'upload_date': parts[4],
                    'summary': parts[5]
                }
                resumes.append(resume)
            except ValueError:
                continue
    return resumes


def write_applications(applications):
    filepath = os.path.join(DATA_DIR, 'applications.txt')
    with open(filepath, 'w', encoding='utf-8') as f:
        for a in applications:
            line = f"{a['application_id']}|{a['job_id']}|{a['applicant_name']}|{a['applicant_email']}|{a['status']}|{a['applied_date']}|{a['resume_id']}"
            f.write(line + '\n')


def write_resumes(resumes):
    filepath = os.path.join(DATA_DIR, 'resumes.txt')
    with open(filepath, 'w', encoding='utf-8') as f:
        for r in resumes:
            line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
            f.write(line + '\n')


