        # Check available seats and update showtime and bookings
        # Simple concurrency not handled

        # Generate new booking_id
        max_id = max((b['booking_id'] for b in bookings), default=0)
        new_booking_id = max_id + 1

        total_price = len(seats_selected) * showtime['price']

