from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Constants for data file paths
DATA_DIR = 'data'
USERS_FILE = os.path.join(DATA_DIR, 'users.txt')
MENU_FILE = os.path.join(DATA_DIR, 'menu.txt')
RESERVATIONS_FILE = os.path.join(DATA_DIR, 'reservations.txt')
WAITLIST_FILE = os.path.join(DATA_DIR, 'waitlist.txt')
REVIEWS_FILE = os.path.join(DATA_DIR, 'reviews.txt')

# --- Helper functions to load and write data ---

def load_users():
    users = {}
    if os.path.exists(USERS_FILE):
        with open(USERS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, full_name = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'full_name': full_name
                    }
    return users


def load_menu():
    menu = []
    if os.path.exists(MENU_FILE):
        with open(MENU_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    dish_id, name, category, price, description, ingredients, dietary, avg_rating = parts
                    try:
                        dish = {
                            'dish_id': int(dish_id),
                            'name': name,
                            'category': category,
                            'price': float(price),
                            'description': description,
                            'ingredients': ingredients,
                            'dietary': dietary,
                            'avg_rating': float(avg_rating)
                        }
                        menu.append(dish)
                    except ValueError:
                        continue
    return menu


def load_reservations():
    reservations = []
    if os.path.exists(RESERVATIONS_FILE):
        with open(RESERVATIONS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # reservation_id|username|guest_name|phone|email|party_size|date|time|special_requests|status
                if len(parts) == 10:
                    try:
                        reservation_id = int(parts[0])
                        username = parts[1]
                        guest_name = parts[2]
                        phone = parts[3]
                        email = parts[4]
                        party_size = int(parts[5])
                        date = parts[6]
                        time = parts[7]
                        special_requests = parts[8]
                        status = parts[9]
                        reservations.append({
                            'reservation_id': reservation_id,
                            'username': username,
                            'guest_name': guest_name,
                            'phone': phone,
                            'email': email,
                            'party_size': party_size,
                            'date': date,
                            'time': time,
                            'special_requests': special_requests,
                            'status': status
                        })
                    except ValueError:
                        continue
    return reservations


def write_reservations(reservations):
    with open(RESERVATIONS_FILE, 'w', encoding='utf-8') as f:
        for r in reservations:
            line = '|'.join([
                str(r['reservation_id']),
                r['username'],
                r['guest_name'],
                r['phone'],
                r['email'],
                str(r['party_size']),
                r['date'],
                r['time'],
                r['special_requests'],
                r['status']
            ])
            f.write(line + '\n')


def load_waitlist():
    waitlist = []
    if os.path.exists(WAITLIST_FILE):
        with open(WAITLIST_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # waitlist_id|username|party_size|join_time|status
                if len(parts) == 5:
                    try:
                        waitlist_id = int(parts[0])
                        username = parts[1]
                        party_size = int(parts[2])
                        join_time = parts[3]
                        status = parts[4]
                        waitlist.append({
                            'waitlist_id': waitlist_id,
                            'username': username,
                            'party_size': party_size,
                            'join_time': join_time,
                            'status': status
                        })
                    except ValueError:
                        continue
    return waitlist


def write_waitlist(waitlist):
    with open(WAITLIST_FILE, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = '|'.join([
                str(w['waitlist_id']),
                w['username'],
                str(w['party_size']),
                w['join_time'],
                w['status']
            ])
            f.write(line + '\n')


def load_reviews():
    reviews = []
    if os.path.exists(REVIEWS_FILE):
        with open(REVIEWS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # review_id|username|dish_id|rating|review_text|review_date
                if len(parts) == 6:
                    try:
                        review_id = int(parts[0])
                        username = parts[1]
                        dish_id = int(parts[2])
                        rating = int(parts[3])
                        review_text = parts[4]
                        review_date = parts[5]
                        reviews.append({
                            'review_id': review_id,
                            'username': username,
                            'dish_id': dish_id,
                            'rating': rating,
                            'review_text': review_text,
                            'review_date': review_date
                        })
                    except ValueError:
                        continue
    return reviews


def write_reviews(reviews):
    with open(REVIEWS_FILE, 'w', encoding='utf-8') as f:
        for r in reviews:
            line = '|'.join([
                str(r['review_id']),
                r['username'],
                str(r['dish_id']),
                str(r['rating']),
                r['review_text'],
                r['review_date']
            ])
            f.write(line + '\n')

# Helper: Get current logged in user username
# Since spec does not specify login system, we assume logged in user is fixed
# For example, we'll assume username='john_diner'

CURRENT_USERNAME = 'john_diner'

def get_current_user():
    users = load_users()
    return users.get(CURRENT_USERNAME) if CURRENT_USERNAME in users else None


# --- Routes ---

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    user = get_current_user()
    username = CURRENT_USERNAME if user else 'Guest'

    # Featured dishes: Let's define featured dishes as top 3 by avg_rating descending
    menu = load_menu()
    featured = sorted(menu, key=lambda x: x.get('avg_rating', 0), reverse=True)[:3]

    # upcoming reservations for user: status Upcoming
    reservations = load_reservations()
    upcoming_reservations = []
    for r in reservations:
        if r['username'] == CURRENT_USERNAME and r['status'] == 'Upcoming':
            upcoming_reservations.append({
                'reservation_id': r['reservation_id'],
                'date': r['date'],
                'time': r['time'],
                'party_size': r['party_size'],
                'status': r['status']
            })

    return render_template('dashboard.html', username=username, featured_dishes=featured, upcoming_reservations=upcoming_reservations)


@app.route('/menu')
def menu():
    menu = load_menu()
    # We provide menus context: list of dict with requested keys
    menus = []
    for dish in menu:
        menus.append({
            'dish_id': dish['dish_id'],
            'name': dish['name'],
            'category': dish['category'],
            'price': dish['price'],
            'description': dish['description'],
            'avg_rating': dish['avg_rating']
        })
    return render_template('menu.html', menus=menus)


@app.route('/dish/<int:dish_id>')
def dish_details(dish_id):
    menu = load_menu()
    dish = None
    for d in menu:
        if d['dish_id'] == dish_id:
            dish = {
                'dish_id': d['dish_id'],
                'name': d['name'],
                'price': d['price'],
                'description': d['description']
            }
            break
    if not dish:
        return "Dish not found", 404
    return render_template('dish_details.html', dish=dish)


@app.route('/make-reservation', methods=['GET', 'POST'])
def make_reservation():
    user = get_current_user()
    if request.method == 'GET':
        # Display form
        return render_template('make_reservation.html')
    else:
        # Process reservation submission
        guest_name = request.form.get('guest_name', '').strip()
        party_size_str = request.form.get('party_size', '').strip()
        reservation_date = request.form.get('reservation_date', '').strip()

        # Validate party_size
        try:
            party_size = int(party_size_str)
            if party_size < 1 or party_size > 10:
                return "Party size must be between 1 and 10", 400
        except ValueError:
            return "Invalid party size", 400

        if not guest_name or not reservation_date:
            return "Missing required fields", 400

        # Validate reservation_date format YYYY-MM-DD
        try:
            datetime.strptime(reservation_date, '%Y-%m-%d')
        except ValueError:
            return "Invalid date format; use YYYY-MM-DD", 400

        # Generate new reservation_id
        reservations = load_reservations()
        max_id = max([r['reservation_id'] for r in reservations], default=0)
        new_id = max_id + 1

        # Prepare new reservation
        new_reservation = {
            'reservation_id': new_id,
            'username': CURRENT_USERNAME,
            'guest_name': guest_name,
            'phone': user['phone'] if user else '',
            'email': user['email'] if user else '',
            'party_size': party_size,
            'date': reservation_date,
            'time': '18:00',  # Spec does not provide time in form, assume default 18:00
            'special_requests': '',
            'status': 'Upcoming'
        }

        reservations.append(new_reservation)
        write_reservations(reservations)

        return render_template('make_reservation.html', submission_status='Reservation submitted successfully.')


@app.route('/my-reservations')
def my_reservations():
    reservations = load_reservations()
    user_reservations = []
    for r in reservations:
        if r['username'] == CURRENT_USERNAME:
            user_reservations.append({
                'reservation_id': r['reservation_id'],
                'date': r['date'],
                'time': r['time'],
                'party_size': r['party_size'],
                'status': r['status']
            })
    return render_template('my_reservations.html', reservations=user_reservations)


@app.route('/cancel-reservation/<int:reservation_id>', methods=['POST'])
def cancel_reservation(reservation_id):
    reservations = load_reservations()
    updated = False
    for r in reservations:
        if r['reservation_id'] == reservation_id and r['username'] == CURRENT_USERNAME:
            if r['status'] == 'Upcoming':
                r['status'] = 'Cancelled'
                updated = True
                break
    if updated:
        write_reservations(reservations)
        return '', 204
    else:
        return '', 404


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    waitlist_entries = load_waitlist()
    user_entry = None

    # Find if user already active in waitlist
    for entry in waitlist_entries:
        if entry['username'] == CURRENT_USERNAME and entry['status'] == 'Active':
            user_entry = entry
            break

    if request.method == 'GET':
        waitlist_position = 0
        user_party_size = 0
        if user_entry:
            # Position is the index+1 of user in all active waitlist entries sorted by join_time
            active_entries = [e for e in waitlist_entries if e['status'] == 'Active']
            sorted_entries = sorted(active_entries, key=lambda x: x['join_time'])
            for idx, entry in enumerate(sorted_entries, start=1):
                if entry['username'] == CURRENT_USERNAME:
                    waitlist_position = idx
                    user_party_size = entry['party_size']
                    break
        return render_template('waitlist.html', waitlist_position=waitlist_position, user_party_size=user_party_size)

    if request.method == 'POST':
        party_size_str = request.form.get('party_size', '').strip()
        try:
            party_size = int(party_size_str)
        except ValueError:
            party_size = 0

        if party_size < 1:
            # Invalid party size
            return render_template('waitlist.html', waitlist_position=0, user_party_size=0)

        # If user already in waitlist active, no duplicate entry, just show current position
        if user_entry and user_entry['status'] == 'Active':
            active_entries = [e for e in waitlist_entries if e['status'] == 'Active']
            sorted_entries = sorted(active_entries, key=lambda x: x['join_time'])
            position = 0
            for idx, entry in enumerate(sorted_entries, start=1):
                if entry['username'] == CURRENT_USERNAME:
                    position = idx
                    break
            return render_template('waitlist.html', waitlist_position=position, user_party_size=user_entry['party_size'])

        # Assign new waitlist id
        max_id = max([e['waitlist_id'] for e in waitlist_entries], default=0)
        new_id = max_id + 1

        now_str = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        new_entry = {
            'waitlist_id': new_id,
            'username': CURRENT_USERNAME,
            'party_size': party_size,
            'join_time': now_str,
            'status': 'Active'
        }

        waitlist_entries.append(new_entry)
        write_waitlist(waitlist_entries)

        # Calculate new position
        active_entries = [e for e in waitlist_entries if e['status'] == 'Active']
        sorted_entries = sorted(active_entries, key=lambda x: x['join_time'])
        position = 0
        for idx, entry in enumerate(sorted_entries, start=1):
            if entry['username'] == CURRENT_USERNAME:
                position = idx
                break

        return render_template('waitlist.html', waitlist_position=position, user_party_size=party_size)


@app.route('/my-reviews')
def my_reviews():
    reviews_all = load_reviews()
    menu = load_menu()

    user_reviews = []
    for r in reviews_all:
        if r['username'] == CURRENT_USERNAME:
            dish_name = next((dish['name'] for dish in menu if dish['dish_id'] == r['dish_id']), '')
            user_reviews.append({
                'review_id': r['review_id'],
                'dish_name': dish_name,
                'rating': r['rating'],
                'review_text': r['review_text']
            })
    return render_template('my_reviews.html', reviews=user_reviews, username=CURRENT_USERNAME)


@app.route('/write-review', methods=['GET', 'POST'])
def write_review():
    menu = load_menu()
    dishes = [{'dish_id': d['dish_id'], 'name': d['name']} for d in menu]

    if request.method == 'GET':
        return render_template('write_review.html', dishes=dishes)

    # POST
    select_dish_str = request.form.get('select_dish', '').strip()
    rating_str = request.form.get('rating', '').strip()
    review_text = request.form.get('review_text', '').strip()

    error_message = None
    success_message = None

    # Validate dish
    try:
        select_dish = int(select_dish_str)
    except ValueError:
        error_message = "Invalid dish selection."
        return render_template('write_review.html', dishes=dishes, error_message=error_message)

    # Validate rating
    try:
        rating = int(rating_str)
        if rating < 1 or rating > 5:
            raise ValueError
    except ValueError:
        error_message = "Rating must be between 1 and 5."
        return render_template('write_review.html', dishes=dishes, error_message=error_message)

    if not review_text:
        error_message = "Review text cannot be empty."
        return render_template('write_review.html', dishes=dishes, error_message=error_message)

    # Generate new review_id
    reviews_all = load_reviews()
    max_id = max([r['review_id'] for r in reviews_all], default=0)
    new_id = max_id + 1

    new_review = {
        'review_id': new_id,
        'username': CURRENT_USERNAME,
        'dish_id': select_dish,
        'rating': rating,
        'review_text': review_text,
        'review_date': datetime.now().strftime('%Y-%m-%d')
    }

    reviews_all.append(new_review)
    write_reviews(reviews_all)

    success_message = "Review submitted successfully."
    return render_template('write_review.html', dishes=dishes, success_message=success_message)


@app.route('/profile', methods=['GET', 'POST'])
def profile():
    user = get_current_user()
    if not user:
        return "User not found", 404

    if request.method == 'GET':
        user_profile = {'username': user['username'], 'email': user['email']}
        return render_template('profile.html', user_profile=user_profile)

    # POST updates profile email
    new_email = request.form.get('profile_email', '').strip()
    if not new_email:
        # Render with old data ignoring update if empty
        user_profile = {'username': user['username'], 'email': user['email']}
        return render_template('profile.html', user_profile=user_profile)

    # Update users.txt
    users = load_users()
    if CURRENT_USERNAME in users:
        users[CURRENT_USERNAME]['email'] = new_email
        # Write back all users
        with open(USERS_FILE, 'w', encoding='utf-8') as f:
            for u in users.values():
                line = '|'.join([u['username'], u['email'], u['phone'], u['full_name']])
                f.write(line + '\n')

    user_profile = {'username': CURRENT_USERNAME, 'email': new_email}
    return render_template('profile.html', user_profile=user_profile)


if __name__ == '__main__':
    app.run(debug=True)

