from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Data file paths
DATA_DIR = 'data'
USERS_FILE = os.path.join(DATA_DIR, 'users.txt')
MENU_FILE = os.path.join(DATA_DIR, 'menu.txt')
RESERVATIONS_FILE = os.path.join(DATA_DIR, 'reservations.txt')
WAITLIST_FILE = os.path.join(DATA_DIR, 'waitlist.txt')
REVIEWS_FILE = os.path.join(DATA_DIR, 'reviews.txt')

# --- Helper functions to load and write data files ---

def load_users():
    users = {}
    if os.path.exists(USERS_FILE):
        with open(USERS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, full_name = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'full_name': full_name
                    }
    return users


def load_menu():
    menu = []
    if os.path.exists(MENU_FILE):
        with open(MENU_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    dish_id, name, category, price, description, ingredients, dietary, avg_rating = parts
                    try:
                        dish = {
                            'dish_id': int(dish_id),
                            'name': name,
                            'category': category,
                            'price': float(price),
                            'description': description,
                            'ingredients': ingredients,
                            'dietary': dietary,
                            'avg_rating': float(avg_rating)
                        }
                        menu.append(dish)
                    except ValueError:
                        continue
    return menu


def load_reservations():
    reservations = []
    if os.path.exists(RESERVATIONS_FILE):
        with open(RESERVATIONS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # reservation_id|username|guest_name|phone|email|party_size|date|time|special_requests|status
                if len(parts) == 10:
                    try:
                        reservation_id = int(parts[0])
                        username = parts[1]
                        guest_name = parts[2]
                        phone = parts[3]
                        email = parts[4]
                        party_size = int(parts[5])
                        date = parts[6]
                        time = parts[7]
                        special_requests = parts[8]
                        status = parts[9]
                        reservations.append({
                            'reservation_id': reservation_id,
                            'username': username,
                            'guest_name': guest_name,
                            'phone': phone,
                            'email': email,
                            'party_size': party_size,
                            'date': date,
                            'time': time,
                            'special_requests': special_requests,
                            'status': status
                        })
                    except ValueError:
                        continue
    return reservations


def write_reservations(reservations):
    with open(RESERVATIONS_FILE, 'w', encoding='utf-8') as f:
        for r in reservations:
            line = '|'.join([
                str(r['reservation_id']),
                r['username'],
                r['guest_name'],
                r['phone'],
                r['email'],
                str(r['party_size']),
                r['date'],
                r['time'],
                r['special_requests'],
                r['status']
            ])
            f.write(line + '\n')


def load_waitlist():
    waitlist = []
    if os.path.exists(WAITLIST_FILE):
        with open(WAITLIST_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # waitlist_id|username|party_size|join_time|status
                if len(parts) == 5:
                    try:
                        waitlist_id = int(parts[0])
                        username = parts[1]
                        party_size = int(parts[2])
                        join_time = parts[3]
                        status = parts[4]
                        waitlist.append({
                            'waitlist_id': waitlist_id,
                            'username': username,
                            'party_size': party_size,
                            'join_time': join_time,
                            'status': status
                        })
                    except ValueError:
                        continue
    return waitlist


def write_waitlist(waitlist):
    with open(WAITLIST_FILE, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = '|'.join([
                str(w['waitlist_id']),
                w['username'],
                str(w['party_size']),
                w['join_time'],
                w['status']
            ])
            f.write(line + '\n')


def load_reviews():
    reviews = []
    if os.path.exists(REVIEWS_FILE):
        with open(REVIEWS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                # review_id|username|dish_id|rating|review_text|review_date
                if len(parts) == 6:
                    try:
                        review_id = int(parts[0])
                        username = parts[1]
                        dish_id = int(parts[2])
                        rating = int(parts[3])
                        review_text = parts[4]
                        review_date = parts[5]
                        reviews.append({
                            'review_id': review_id,
